const isMeaningful = (value) => {
  if (value === null || value === undefined) return false;
  if (typeof value === 'string') return value.trim() !== '';
  return true;
};

const pickValue = (...values) => {
  for (const value of values) {
    if (isMeaningful(value)) return value;
  }
  return undefined;
};

const parseJsonObject = (raw) => {
  if (typeof raw !== 'string') return null;
  const text = raw.trim();
  if (!text) return null;
  try {
    const parsed = JSON.parse(text);
    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
      return parsed;
    }
  } catch {
    return null;
  }
  return null;
};

const parseTruthyDryRun = (value) => {
  if (value === true || value === 1) return true;
  if (typeof value === 'string') {
    const lowered = value.trim().toLowerCase();
    return lowered === 'true' || lowered === '1';
  }
  return false;
};

const toOptionalInt = (value) => {
  if (!isMeaningful(value)) return null;
  const num = Number(value);
  if (!Number.isFinite(num)) return null;
  return Math.floor(num);
};

const toOptionalString = (value) => {
  if (!isMeaningful(value)) return '';
  return String(value).trim();
};

return items.map((item) => {
  const root = (item && item.json && typeof item.json === 'object') ? item.json : {};

  let payload = root;
  let payloadSource = 'root';

  if (root.body && typeof root.body === 'object' && !Array.isArray(root.body)) {
    payload = root.body;
    payloadSource = 'body_object';
  } else if (typeof root.body === 'string') {
    const parsedBody = parseJsonObject(root.body);
    if (parsedBody) {
      payload = parsedBody;
      payloadSource = 'body_json_string';
    } else {
      payload = root;
      payloadSource = 'body_string_unparsed';
    }
  }

  const cid = toOptionalString(pickValue(payload.cid, root.cid));
  const sendUserId = toOptionalString(pickValue(payload.send_user_id, payload.sendUserId, root.send_user_id, root.sendUserId));
  const sendMessage = toOptionalString(pickValue(payload.send_message, payload.sendMessage, root.send_message, root.sendMessage));

  const contentTypeRaw = pickValue(payload.content_type, payload.contentType, root.content_type, root.contentType);
  const contentTypeNum = toOptionalInt(contentTypeRaw);
  const contentType = contentTypeNum !== null ? contentTypeNum : toOptionalString(contentTypeRaw);

  const dryRunRaw = pickValue(payload.dry_run, payload.dryRun, root.dry_run, root.dryRun);
  const dryRun = parseTruthyDryRun(dryRunRaw);

  const cooldownSeconds = toOptionalInt(pickValue(payload.cooldown_seconds, payload.cooldownSeconds, root.cooldown_seconds, root.cooldownSeconds));
  const maxReplyChars = toOptionalInt(pickValue(payload.max_reply_chars, payload.maxReplyChars, root.max_reply_chars, root.maxReplyChars));
  const itemId = toOptionalString(pickValue(payload.item_id, payload.itemId, root.item_id, root.itemId));

  return {
    json: {
      event: toOptionalString(pickValue(payload.event, root.event)),
      cid,
      send_user_id: sendUserId,
      send_message: sendMessage,
      content_type: contentType,
      dry_run: dryRun,
      cooldown_seconds: cooldownSeconds,
      max_reply_chars: maxReplyChars,
      item_id: itemId,
      send_user_name: toOptionalString(pickValue(payload.send_user_name, payload.sendUserName, root.send_user_name, root.sendUserName)),
      image_url: toOptionalString(pickValue(payload.image_url, payload.imageUrl, root.image_url, root.imageUrl)),
      original_payload: payload,
      webhook_meta: {
        payload_source: payloadSource,
        headers: root.headers && typeof root.headers === 'object' ? root.headers : {},
        query: root.query && typeof root.query === 'object' ? root.query : {},
        params: root.params && typeof root.params === 'object' ? root.params : {},
      },
    },
  };
});

const staticData = $getWorkflowStaticData('global');
const MAX_DEDUP_KEYS = 500;

const isTruthy = (value) => {
  if (value === true || value === 1) return true;
  if (typeof value === 'string') {
    const lowered = value.trim().toLowerCase();
    return lowered === 'true' || lowered === '1';
  }
  return false;
};

const getDedupStore = () => {
  if (!staticData.dedupStore || typeof staticData.dedupStore !== 'object') {
    staticData.dedupStore = { order: [], map: {} };
  }
  const dedupStore = staticData.dedupStore;
  if (!Array.isArray(dedupStore.order)) dedupStore.order = [];
  if (!dedupStore.map || typeof dedupStore.map !== 'object') dedupStore.map = {};
  return dedupStore;
};

return items.map((item) => {
  const cid = String(item.json.cid ?? '').trim();
  const sendUserId = String(item.json.send_user_id ?? '').trim();
  const sendMessage = String(item.json.send_message ?? '').trim();
  const dedupKey = `${cid}::${sendUserId}::${sendMessage}`;
  const isDryRun = isTruthy(item.json.dry_run);

  if (isDryRun) {
    return {
      json: {
        ...item.json,
        dry_run: true,
        dedup_key: dedupKey,
        is_duplicate: false,
        dedup_skipped: true,
        dedup_skip_reason: 'dry_run',
      },
    };
  }

  const dedupStore = getDedupStore();
  const isDuplicate = Boolean(dedupStore.map[dedupKey]);

  if (!isDuplicate) {
    dedupStore.map[dedupKey] = Date.now();
    dedupStore.order.push(dedupKey);

    while (dedupStore.order.length > MAX_DEDUP_KEYS) {
      const oldest = dedupStore.order.shift();
      if (oldest) delete dedupStore.map[oldest];
    }
  }

  if (isDuplicate) {
    return {
      json: {
        ...item.json,
        dedup_key: dedupKey,
        is_duplicate: true,
        ok: true,
        send: false,
        reason: 'duplicate_message',
        message: 'duplicate message skipped',
        cid,
        send_user_id: sendUserId,
      },
    };
  }

  return {
    json: {
      ...item.json,
      dedup_key: dedupKey,
      is_duplicate: false,
    },
  };
});

const isTruthy = (value) => {
  if (value === true || value === 1) return true;
  if (typeof value === 'string') {
    const lowered = value.trim().toLowerCase();
    return lowered === 'true' || lowered === '1';
  }
  return false;
};

if (isTruthy($json.dry_run)) {
  return [{
    json: {
      ok: true,
      send: false,
      reason: 'dry_run_dedup_guard',
      message: 'dry_run should not enter duplicate branch',
      cid: $json.cid ?? '',
      send_user_id: $json.send_user_id ?? '',
      dry_run: true,
      is_duplicate: false,
      dedup_skipped: true,
      dedup_skip_reason: 'dry_run',
    },
  }];
}

return [{
  json: {
    ok: true,
    send: false,
    reason: 'duplicate_message',
    message: 'duplicate message skipped',
    cid: $json.cid ?? '',
    send_user_id: $json.send_user_id ?? '',
  },
}];

return items.map((item) => ({
  json: {
    ...item.json,
    original: item.json,
  },
}));

const saved = $("保留原始入站消息").item.json;
const original = saved.original ?? saved;
return [{ json: { ...original } }];

const staticData = $getWorkflowStaticData('global');
const now = Date.now();

const getCooldownStore = () => {
  if (!staticData.cooldownStore || typeof staticData.cooldownStore !== 'object') {
    staticData.cooldownStore = {};
  }
  return staticData.cooldownStore;
};

return items.map((item) => {
  const cid = String(item.json.cid ?? '').trim();
  const cooldownRaw = Number(item.json.cooldown_seconds);
  const cooldownSeconds = Number.isFinite(cooldownRaw) && cooldownRaw > 0 ? Math.floor(cooldownRaw) : 15;
  const isDryRun = [true, 'true', 1, '1'].includes(item.json.dry_run);

  if (isDryRun) {
    return {
      json: {
        ...item.json,
        dry_run: true,
        cooldown_active: false,
        cooldown_skipped: true,
        cooldown_skip_reason: 'dry_run',
        cooldown_seconds: cooldownSeconds,
      },
    };
  }

  const cooldownStore = getCooldownStore();
  const lastAllowedAt = Number(cooldownStore[cid] ?? 0);
  const elapsedSeconds = (now - lastAllowedAt) / 1000;

  if (cid && lastAllowedAt > 0 && elapsedSeconds < cooldownSeconds) {
    const remainingSeconds = Math.max(1, Math.ceil(cooldownSeconds - elapsedSeconds));
    return {
      json: {
        ...item.json,
        cooldown_active: true,
        ok: true,
        send: false,
        reason: 'cooldown_active',
        message: 'conversation cooldown active',
        cid,
        cooldown_seconds: cooldownSeconds,
        remaining_seconds: remainingSeconds,
      },
    };
  }

  if (cid) {
    cooldownStore[cid] = now;
  }

  return {
    json: {
      ...item.json,
      cooldown_active: false,
      cooldown_seconds: cooldownSeconds,
    },
  };
});

return [{
  json: {
    ok: true,
    send: false,
    reason: 'cooldown_active',
    message: 'conversation cooldown active',
    cid: $json.cid ?? '',
    cooldown_seconds: Number($json.cooldown_seconds ?? 15),
    remaining_seconds: Number($json.remaining_seconds ?? 0),
  },
}];

return items.map((item) => ({
  json: {
    ...item.json,
    handoff: false,
    handoff_reason: '',
    route_reason: String(item.json.route_reason || 'default_openclaw'),
    should_send: true,
    rule_reply: '',
  },
}));

return items.map((item) => ({
  json: {
    ...item.json,
    item_context_original: JSON.parse(JSON.stringify(item.json || {})),
  },
}));

const sourceItems = $("保留商品上下文请求原始 payload").all();

const pickText = (value) => {
  if (typeof value === 'string' && value.trim()) return value.trim();
  return '';
};

return items.map((item, index) => {
  const snapshot = item.json || {};
  const sourceWrapper = (sourceItems[index] && sourceItems[index].json) || {};
  const original = sourceWrapper.item_context_original || sourceWrapper || {};

  let item_context = null;
  let item_context_status = 'missing';
  let item_context_reason = 'snapshot_unavailable';

  if (snapshot.ok === true) {
    item_context = {
      available: true,
      source: 'items_snapshot',
      item_count: Number(snapshot.item_count ?? 0),
      items: Array.isArray(snapshot.items) ? snapshot.items : [],
      section_counts: snapshot.section_counts || {},
      metadata: snapshot.metadata || {},
    };
    item_context_status = 'available';
    item_context_reason = '';
  } else if (pickText(snapshot.reason)) {
    item_context_status = 'missing';
    item_context_reason = pickText(snapshot.reason);
  } else if (pickText(snapshot.error?.message) || pickText(snapshot.error)) {
    item_context_status = 'error';
    item_context_reason = pickText(snapshot.error?.message) || pickText(snapshot.error);
  } else if (pickText(snapshot.message)) {
    item_context_status = 'error';
    item_context_reason = pickText(snapshot.message);
  }

  return {
    json: {
      ...original,
      cid: original.cid,
      send_user_id: original.send_user_id,
      send_message: original.send_message,
      content_type: original.content_type,
      dry_run: original.dry_run,
      risk: original.risk,
      risk_reason: original.risk_reason,
      handoff: original.handoff,
      handoff_reason: original.handoff_reason,
      route_reason: original.route_reason,
      should_send: original.should_send,
      cooldown_seconds: original.cooldown_seconds,
      max_reply_chars: original.max_reply_chars,
      item_context,
      item_context_status,
      item_context_reason,
    },
  };
});

return items.map((item) => ({
  json: {
    ...item.json,
    openclaw_context: JSON.parse(JSON.stringify(item.json || {})),
  },
}));

const contextItems = $("保留 OpenClaw 请求上下文").all();

const pickText = (value) => {
  if (typeof value === 'string' && value.trim()) return value.trim();
  return '';
};

const parseBool = (value) => {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  if (typeof value === 'string') {
    const lower = value.trim().toLowerCase();
    if (['true', '1', 'yes', 'y'].includes(lower)) return true;
    if (['false', '0', 'no', 'n'].includes(lower)) return false;
  }
  return null;
};

const stripMarkdownFences = (raw) => {
  if (typeof raw !== 'string') return '';
  const trimmed = raw.trim();
  if (!trimmed) return '';

  const jsonPrefix = trimmed.match(/^json\s*\n([\s\S]*)$/i);
  if (jsonPrefix && jsonPrefix[1]) return jsonPrefix[1].trim();

  const fullFence = trimmed.match(/^```(?:json)?\s*([\s\S]*?)\s*```$/i);
  if (fullFence && fullFence[1]) return fullFence[1].trim();

  const firstFence = trimmed.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (firstFence && firstFence[1]) return firstFence[1].trim();

  return trimmed;
};

const parseObject = (value) => {
  if (!value) return null;
  if (typeof value === 'object') return value;
  if (typeof value === 'string') {
    const text = stripMarkdownFences(value);
    if (!text) return null;
    try {
      const parsed = JSON.parse(text);
      if (parsed && typeof parsed === 'object') return parsed;
    } catch {
      return null;
    }
  }
  return null;
};

const collectObjects = (response) => {
  const objects = [];
  const pushIfObject = (value) => {
    const parsed = parseObject(value);
    if (parsed) objects.push(parsed);
  };

  pushIfObject(response);
  pushIfObject(response?.data);
  pushIfObject(response?.result);
  pushIfObject(response?.output);
  pushIfObject(response?.response);
  pushIfObject(response?.payload);
  pushIfObject(response?.data?.result);
  pushIfObject(response?.data?.output);
  pushIfObject(response?.output?.result);

  return objects;
};

return items.map((item, index) => {
  const rawResponse = item.json || {};
  const response = parseObject(rawResponse) || rawResponse;
  const contextWrapper = (contextItems[index] && contextItems[index].json) || {};
  const context = contextWrapper.openclaw_context || contextWrapper || {};

  const runtimeMode = String(($env.OPENCLAW_RUNTIME_MODE || 'custom_reply')).trim().toLowerCase() || 'custom_reply';
  const objects = collectObjects(response);

  const replyCandidates = [];
  for (const obj of objects) {
    replyCandidates.push(['reply', obj.reply]);
    replyCandidates.push(['text', obj.text]);
    replyCandidates.push(['message', obj.message]);
    replyCandidates.push(['content', obj.content]);
    replyCandidates.push(['final_reply', obj.final_reply]);
    replyCandidates.push(['answer', obj.answer]);
    replyCandidates.push(['choices[0].message.content', obj.choices?.[0]?.message?.content]);
    replyCandidates.push(['choices[0].text', obj.choices?.[0]?.text]);
  }

  let openclawReply = '';
  let source = 'none';
  for (const [name, value] of replyCandidates) {
    const text = pickText(value);
    if (text) {
      openclawReply = text;
      source = name;
      break;
    }
  }

  // If chat completions content itself is JSON, parse it to recover reply/should_send/handoff/reason.
  let contentObject = null;
  if (source === 'choices[0].message.content') {
    contentObject = parseObject(openclawReply);
  }
  if (contentObject) {
    objects.unshift(contentObject);
    const contentReply = pickText(contentObject.reply);
    if (contentReply) {
      openclawReply = contentReply;
      source = 'choices[0].message.content.reply';
    } else {
      openclawReply = '';
      source = 'choices[0].message.content.object';
    }
  }

  const boolCandidates = [];
  for (const obj of objects) {
    boolCandidates.push(['handoff', obj.handoff]);
    boolCandidates.push(['need_handoff', obj.need_handoff]);
    boolCandidates.push(['needs_handoff', obj.needs_handoff]);
    boolCandidates.push(['needs_human', obj.needs_human]);
    boolCandidates.push(['human_handoff', obj.human_handoff]);
  }

  let handoff = null;
  for (const [, value] of boolCandidates) {
    const parsed = parseBool(value);
    if (parsed !== null) {
      handoff = parsed;
      break;
    }
  }
  if (handoff === null) handoff = false;

  const sendCandidates = [];
  for (const obj of objects) {
    sendCandidates.push(['should_send', obj.should_send]);
    sendCandidates.push(['shouldSend', obj.shouldSend]);
    sendCandidates.push(['send', obj.send]);
  }

  let shouldSend = null;
  for (const [, value] of sendCandidates) {
    const parsed = parseBool(value);
    if (parsed !== null) {
      shouldSend = parsed;
      break;
    }
  }
  if (shouldSend === null) {
    shouldSend = handoff ? false : true;
  }

  const reasonCandidates = [];
  for (const obj of objects) {
    reasonCandidates.push(obj.reason);
    reasonCandidates.push(obj.handoff_reason);
    reasonCandidates.push(obj.route_reason);
    reasonCandidates.push(obj.block_reason);
  }

  let openclawReason = '';
  for (const value of reasonCandidates) {
    const text = pickText(value);
    if (text) {
      openclawReason = text;
      break;
    }
  }

  const errorCandidates = [];
  for (const obj of objects) {
    errorCandidates.push(obj.error?.message);
    errorCandidates.push(obj.error);
    errorCandidates.push(obj.err);
    errorCandidates.push(obj.exception);
    errorCandidates.push(obj.message && String(obj.message).includes('status code') ? obj.message : '');
  }
  errorCandidates.push(response?.error?.message);
  errorCandidates.push(response?.error);

  let openclawError = '';
  for (const value of errorCandidates) {
    const text = pickText(value);
    if (text) {
      openclawError = text;
      break;
    }
  }

  // HTML or non-JSON content from upstream is treated as runtime error for fail-closed.
  if (!openclawError && runtimeMode === 'openai_chat' && source === 'choices[0].message.content') {
    const maybeHtml = openclawReply.trim().toLowerCase();
    if (maybeHtml.startsWith('<!doctype html') || maybeHtml.startsWith('<html')) {
      openclawError = 'openclaw_html_response';
    }
  }

  return {
    json: {
      ...context,
      cid: context.cid,
      send_user_id: context.send_user_id,
      send_message: context.send_message,
      risk: context.risk,
      risk_reason: context.risk_reason,
      route_reason: context.route_reason,
      openclaw_runtime_mode: runtimeMode,
      handoff,
      handoff_reason: handoff ? (openclawReason || String(context.handoff_reason || 'openclaw_handoff')) : String(context.handoff_reason || ''),
      should_send: shouldSend,
      reply: openclawReply,
      openclaw_reply: openclawReply,
      openclaw_response: response,
      openclaw_reply_source: source,
      openclaw_reason: openclawReason,
      openclaw_error: openclawError,
      item_context_status: context.item_context_status,
      item_context_reason: context.item_context_reason,
      cooldown_seconds: context.cooldown_seconds,
      max_reply_chars: context.max_reply_chars,
    },
  };
});

const maxReplyChars = Number($json.max_reply_chars || 80);
const blocked = /(微信|QQ|支付宝|银行卡|线下|转账|私聊|加我)/i;
let text = String($json.reply || '').replace(/<think>[\s\S]*?<\/think>/gi, ' ');
text = text.replace(/```(?:thinking|reasoning|analysis)[\s\S]*?```/gi, ' ');
const markers = ['最终回复：','最终回复:','买家可见回复：','买家可见回复:','回复：','回复:'];
for (const marker of markers) {
  const idx = text.lastIndexOf(marker);
  if (idx >= 0) text = text.slice(idx + marker.length);
}
text = text.split(/\r?\n/)
  .map((line) => line.replace(/^\s*(?:[-*+]|#{1,6}|>|\d+[.)])\s*/, '').trim())
  .filter((line) => line && !/^(思考|分析|推理|判断|策略|步骤|理由|reasoning|analysis)/i.test(line))
  .join(' ')
  .replace(/\s+/g, ' ')
  .trim();
if (blocked.test(text)) text = '平台内沟通就行，合适可拍';
text = text.slice(0, maxReplyChars);
return [{ json: { ...$json, sanitized_reply: text } }];

let final_reply = String($json.sanitized_reply || '').trim();
if (/(微信|QQ|支付宝|银行卡|线下|转账|私聊|加我)/i.test(final_reply)) {
  final_reply = '平台内沟通就行，合适可拍';
}
return [{ json: { ...$json, final_reply } }];

const toTrue = (value) => [true, 'true', 1, '1'].includes(value);
const toFalse = (value) => [false, 'false', 0, '0'].includes(value);

const finalReply = String($json.final_reply || '').trim();
const openclawError = String($json.openclaw_error || '').trim();
const openclawReason = String($json.openclaw_reason || '').trim();

let handoff = toTrue($json.handoff);
let handoffReason = String($json.handoff_reason || '').trim();
let shouldSend = !toFalse($json.should_send);
let routeReason = String($json.route_reason || 'default_openclaw').trim() || 'default_openclaw';

if (openclawError) {
  handoff = true;
  shouldSend = false;
  routeReason = 'system_exception';
  if (!handoffReason) {
    handoffReason = `openclaw_error:${openclawError.slice(0, 160)}`;
  }
} else if (handoff) {
  shouldSend = false;
  routeReason = 'openclaw_handoff';
  if (!handoffReason) {
    handoffReason = openclawReason || 'openclaw_requested_handoff';
  }
} else if (!shouldSend) {
  routeReason = 'openclaw_should_send_false';
  if (!handoffReason) {
    handoffReason = openclawReason || 'openclaw_blocked_send';
  }
} else if (!finalReply) {
  handoff = true;
  shouldSend = false;
  routeReason = 'openclaw_no_valid_reply';
  if (!handoffReason) {
    handoffReason = 'openclaw_no_valid_reply';
  }
}

const reason = shouldSend ? 'ready_to_send' : (routeReason || 'blocked');

return [{
  json: {
    ...$json,
    send: shouldSend,
    should_send: shouldSend,
    handoff,
    handoff_reason: handoffReason,
    route_reason: routeReason,
    reason,
    final_reply: finalReply,
  },
}];
